p.m:
\displaystyle{\begin{aligned}
   45\div \frac{9}{2} 
       \amp = \frac{45}{1} \div \frac{9}{2} \\
       \amp = \frac{45}{1} \cdot \frac{2}{9} \amp \hbox{We can divide 45 and 9 by 9 and made those two values smaller.}\\
       \amp = \frac{5}{1}\cdot\frac{2}{1} \\
       \amp = \frac{5\cdot2}{1 \cdot 1} \\
       \amp = 10
\end{aligned}
    }
